def longest_increasing_subsequence(nums) -> int:
    import bisect
    if not nums:
        return 0
    dp = []
    for num in nums:
        idx = bisect.bisect_left(dp, num)
        if idx == len(dp):
            dp.append(num)
        else:
            dp[idx] = num
    return len(dp)
